try:
    wm = spark.sql(
        f"SELECT last_ingest_time, updated_at "
        f"FROM odw_meta_db.service_bus_watermarks "
        f"WHERE entity = '{entity_name}' AND source = 'service-bus'"
    ).collect()
    if wm:
        print(f'Current watermark : {wm[0]["last_ingest_time"]}')
        print('Test messages will use utcnow() — they will be newer than this watermark.')
    else:
        print('No watermark found — all records will be processed (first run).')
except Exception as e:
    print(f'Could not read watermark table (may not exist yet): {e}')

# These columns are added by read_raw_messages — not present in raw JSON files
_COMPUTED_COLUMNS = {'ingested_datetime', 'expected_from', 'expected_to', 'input_file'}

schema_json = mssparkutils.notebook.run(
    '/py_create_spark_schema',
    60,
    {'db_name': 'odw_standardised_db', 'entity_name': entity_name}
)
spark_schema: StructType = StructType.fromJson(json.loads(schema_json))
raw_fields = [f for f in spark_schema.fields if f.name not in _COMPUTED_COLUMNS]
print(f'Schema loaded: {len(raw_fields)} fields (excluding computed columns)')

enqueued_time = override_enqueued_time or datetime.now(timezone.utc).strftime('%Y-%m-%dT%H:%M:%SZ')


def _default_value(field: StructField, index: int) -> object:
    name = field.name
    if name == primary_key:
        return 99000 + index if isinstance(field.dataType, (LongType, IntegerType, ShortType, ByteType)) else f'TEST-{entity_name}-{index:04d}'
    if name == watermark_column:
        return enqueued_time
    if name == 'message_id':
        return str(uuid.uuid4())
    if name == 'message_type':
        return 'Create'
    if isinstance(field.dataType, BooleanType):
        return False
    if isinstance(field.dataType, ArrayType):
        return []
    return None


mssparkutils.fs.mkdirs(base_path)

for i in range(1, num_messages + 1):
    msg = {f.name: _default_value(f, i) for f in raw_fields}
    file_path = f"{base_path}/{msg['message_id']}.json"
    mssparkutils.fs.put(file_path, json.dumps(msg), True)
    print(f'  [{i}/{num_messages}] {file_path}')

print(f'\nDone. {num_messages} message(s) seeded for "{entity_name}"')
print(f'{watermark_column} = {enqueued_time}')
print(f'\nRun pln_service_bus with entity_name_array=["{entity_name}"] to process.')
